## Goal

Add `denied`, `access`, and `agent` params to the agents route search schema and update the AppShell header slot to recognize all 4 view modes.

## File 1: `apps/client/src/router.tsx`

At line 64, the current `agentsSearchSchema` only supports 2 views:

```typescript
const agentsSearchSchema = mergeDialogSearch(
  z
    .object({
      view: z.enum(['list', 'topology']).optional().default('list'),
      sort: z.string().optional().default('lastSeen:desc'),
    })
    .merge(agentFilterSchema.searchValidator)
);
```

Replace the `view` enum and add an `agent` param:

```typescript
const agentsSearchSchema = mergeDialogSearch(
  z
    .object({
      view: z.enum(['list', 'topology', 'denied', 'access']).optional().default('list'),
      sort: z.string().optional().default('lastSeen:desc'),
      agent: z.string().optional(), // selected agent ID for topology detail panel
    })
    .merge(agentFilterSchema.searchValidator)
);
```

## File 2: `apps/client/src/AppShell.tsx`

At line 97-105, the `useHeaderSlot` function's `/agents` case currently resolves viewMode to only `list` or `topology`:

```typescript
case '/agents': {
  const viewParam = new URLSearchParams(searchStr).get('view');
  const viewMode = viewParam === 'topology' ? 'topology' : 'list';
  return {
    key: 'agents',
    content: <AgentsHeader viewMode={viewMode} />,
    borderStyle: undefined,
  };
}
```

Replace the viewMode resolution to support all 4 values:

```typescript
case '/agents': {
  const viewParam = new URLSearchParams(searchStr).get('view');
  const validViews = ['list', 'topology', 'denied', 'access'] as const;
  const viewMode = validViews.includes(viewParam as any)
    ? (viewParam as ViewMode)
    : 'list';
  return {
    key: 'agents',
    content: <AgentsHeader viewMode={viewMode} />,
    borderStyle: undefined,
  };
}
```

You will need to import the `ViewMode` type from AgentsHeader (or define it inline). The AgentsHeader `ViewMode` type will be updated in task 1.6, but the AppShell just needs to pass through the string.

## Acceptance Criteria

- `?view=denied` and `?view=access` are valid search params on the `/agents` route
- `?agent=some-id` is a valid optional search param on the `/agents` route
- The AppShell header slot correctly passes `denied` and `access` view modes to `AgentsHeader`
- Invalid view values fall back to `'list'`

## Goal

Extract the inline `DeniedTab` from `MeshPanel.tsx` into a standalone `DeniedView` component that owns its own data fetching.

## File 1 (Create): `apps/client/src/layers/features/agents-list/ui/DeniedView.tsx`

The existing `DeniedTab` in `MeshPanel.tsx` (lines 20-61) receives `denied` and `isLoading` as props. The new `DeniedView` should own its own data fetching via `useDeniedAgents()` from `@/layers/entities/mesh`.

Complete component implementation:

```typescript
import { Loader2, ShieldCheck } from 'lucide-react';
import { useDeniedAgents } from '@/layers/entities/mesh';
import { MeshEmptyState } from '@/layers/features/mesh';
import { Badge } from '@/layers/shared/ui';

/** Denied agents view — shows blocked paths with denial metadata. */
export function DeniedView() {
  const { data: deniedResult, isLoading } = useDeniedAgents();
  const denied = deniedResult?.denied ?? [];

  if (isLoading) {
    return (
      <div className="flex items-center justify-center p-8">
        <Loader2 className="text-muted-foreground size-5 animate-spin" />
      </div>
    );
  }

  if (denied.length === 0) {
    return (
      <MeshEmptyState
        icon={ShieldCheck}
        headline="No blocked paths"
        description="When you deny agent paths during discovery, they appear here. This is a healthy state."
      />
    );
  }

  return (
    <div className="space-y-2 p-4">
      {denied.map((d) => (
        <div key={d.path} className="flex items-center justify-between rounded-xl border px-4 py-3">
          <div>
            <p className="font-mono text-sm">{d.path}</p>
            {d.reason && <p className="text-muted-foreground text-xs">{d.reason}</p>}
          </div>
          <Badge variant="outline" className="text-xs">
            {d.deniedBy}
          </Badge>
        </div>
      ))}
    </div>
  );
}
```

## File 2 (Create): `apps/client/src/layers/features/agents-list/__tests__/DeniedView.test.tsx`

Write tests following the project testing patterns (vitest-environment jsdom directive, mock entity hooks, QueryClientProvider wrapper):

```typescript
/**
 * @vitest-environment jsdom
 */
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { render, screen, cleanup } from '@testing-library/react';
import '@testing-library/jest-dom/vitest';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import type { ReactNode } from 'react';

// ---------------------------------------------------------------------------
// Mocks
// ---------------------------------------------------------------------------

const mockUseDeniedAgents = vi.fn();

vi.mock('@/layers/entities/mesh', () => ({
  useDeniedAgents: () => mockUseDeniedAgents(),
}));

vi.mock('@/layers/features/mesh', () => ({
  MeshEmptyState: ({ headline }: { headline: string }) => (
    <div data-testid="mesh-empty-state">{headline}</div>
  ),
}));

import { DeniedView } from '../ui/DeniedView';

function createWrapper() {
  const queryClient = new QueryClient({
    defaultOptions: { queries: { retry: false, gcTime: 0 } },
  });
  return ({ children }: { children: ReactNode }) => (
    <QueryClientProvider client={queryClient}>{children}</QueryClientProvider>
  );
}

afterEach(cleanup);

describe('DeniedView', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('renders loading state with spinner', () => {
    mockUseDeniedAgents.mockReturnValue({ data: undefined, isLoading: true });
    render(<DeniedView />, { wrapper: createWrapper() });
    // Loader2 has animate-spin class
    expect(document.querySelector('.animate-spin')).toBeInTheDocument();
  });

  it('renders empty state when no denied paths', () => {
    mockUseDeniedAgents.mockReturnValue({ data: { denied: [] }, isLoading: false });
    render(<DeniedView />, { wrapper: createWrapper() });
    expect(screen.getByTestId('mesh-empty-state')).toBeInTheDocument();
    expect(screen.getByText('No blocked paths')).toBeInTheDocument();
  });

  it('renders list of denied paths with metadata', () => {
    mockUseDeniedAgents.mockReturnValue({
      data: {
        denied: [
          { path: '/opt/agents/bad', reason: 'Not authorized', deniedBy: 'admin' },
          { path: '/tmp/test', reason: null, deniedBy: 'user' },
        ],
      },
      isLoading: false,
    });
    render(<DeniedView />, { wrapper: createWrapper() });
    expect(screen.getByText('/opt/agents/bad')).toBeInTheDocument();
    expect(screen.getByText('Not authorized')).toBeInTheDocument();
    expect(screen.getByText('admin')).toBeInTheDocument();
    expect(screen.getByText('/tmp/test')).toBeInTheDocument();
    expect(screen.getByText('user')).toBeInTheDocument();
  });

  it('does not render reason when reason is null', () => {
    mockUseDeniedAgents.mockReturnValue({
      data: {
        denied: [{ path: '/tmp/test', reason: null, deniedBy: 'user' }],
      },
      isLoading: false,
    });
    render(<DeniedView />, { wrapper: createWrapper() });
    expect(screen.getByText('/tmp/test')).toBeInTheDocument();
    // Only the path and badge should be present, no reason text
    const paragraphs = document.querySelectorAll('p');
    // One <p> for path, none for reason (since reason is null)
    expect(paragraphs.length).toBe(1);
  });
});
```

## Acceptance Criteria

- `DeniedView` renders a loading spinner when `useDeniedAgents` is loading
- `DeniedView` renders `MeshEmptyState` with "No blocked paths" when denied array is empty
- `DeniedView` renders each denied entry with path, optional reason, and deniedBy badge
- All 4 tests pass

